-- Gym56 — Additional Exercise Seed Data (200 exercises)
-- Generated script — inserts new exercises across all categories
DO $$
DECLARE
  cable_crossover_id UUID;
  lat_pulldown_id UUID;
  pec_deck_id UUID;
  leg_press_id UUID;
  adjustable_bench_id UUID;
  leg_extension_id UUID;
  flat_bench_id UUID;
  power_rack_id UUID;
  treadmill_id UUID;
  spin_bike_id UUID;
  dumbbell_rack_id UUID;
  barbell_id UUID;
  ez_curl_id UUID;
  weight_plates_id UUID;
  exercise_mat_id UUID;
  resistance_bands_id UUID;
  kettlebell_id UUID;
  medicine_ball_id UUID;
  pull_up_bar_id UUID;
  battle_ropes_id UUID;
  box_platform_id UUID;
  ab_wheel_id UUID;
  foam_roller_id UUID;
  slam_ball_id UUID;
  sled_id UUID;
  cable_rope_attachment_id UUID;
BEGIN
  SELECT id INTO cable_crossover_id FROM equipment WHERE slug = 'cable-crossover-functional-trainer';
  SELECT id INTO lat_pulldown_id FROM equipment WHERE slug = 'lat-pulldown-low-row';
  SELECT id INTO pec_deck_id FROM equipment WHERE slug = 'pec-deck-rear-delt-fly';
  SELECT id INTO leg_press_id FROM equipment WHERE slug = 'leg-press-hack-squat';
  SELECT id INTO adjustable_bench_id FROM equipment WHERE slug = 'adjustable-flat-incline-bench';
  SELECT id INTO leg_extension_id FROM equipment WHERE slug = 'leg-extension-leg-curl';
  SELECT id INTO flat_bench_id FROM equipment WHERE slug = 'flat-bench-press-station';
  SELECT id INTO power_rack_id FROM equipment WHERE slug = 'hkf-strength-power-rack';
  SELECT id INTO treadmill_id FROM equipment WHERE slug = 'cardio-fitness-treadmills';
  SELECT id INTO spin_bike_id FROM equipment WHERE slug = 'spin-bikes';
  SELECT id INTO dumbbell_rack_id FROM equipment WHERE slug = 'dumbbell-rack';
  SELECT id INTO barbell_id FROM equipment WHERE slug = 'barbells';
  SELECT id INTO ez_curl_id FROM equipment WHERE slug = 'ez-curl-bar';
  SELECT id INTO weight_plates_id FROM equipment WHERE slug = 'weight-plates';
  SELECT id INTO exercise_mat_id FROM equipment WHERE slug = 'exercise-mat';
  SELECT id INTO resistance_bands_id FROM equipment WHERE slug = 'resistance-bands';
  SELECT id INTO kettlebell_id FROM equipment WHERE slug = 'kettlebell';
  SELECT id INTO medicine_ball_id FROM equipment WHERE slug = 'medicine-ball';
  SELECT id INTO pull_up_bar_id FROM equipment WHERE slug = 'pull-up-bar';
  SELECT id INTO battle_ropes_id FROM equipment WHERE slug = 'battle-ropes';
  SELECT id INTO box_platform_id FROM equipment WHERE slug = 'box-platform';
  SELECT id INTO ab_wheel_id FROM equipment WHERE slug = 'ab-wheel';
  SELECT id INTO foam_roller_id FROM equipment WHERE slug = 'foam-roller';
  SELECT id INTO slam_ball_id FROM equipment WHERE slug = 'slam-ball';
  SELECT id INTO sled_id FROM equipment WHERE slug = 'sled';
  SELECT id INTO cable_rope_attachment_id FROM equipment WHERE slug = 'cable-rope-attachment';

  VALUES ('Exercise Mat', 'exercise-mat', 'Functional', 'High-density foam exercise mat for floor workouts, stretching, and core training.', 10, 'excellent', 'Gym Floor', TRUE, TRUE, 14)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Resistance Bands Set', 'resistance-bands', 'Functional', 'Set of resistance bands with varying tension levels for assisted exercises and mobility work.', 6, 'excellent', 'Gym Floor', TRUE, TRUE, 15)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Kettlebell Set', 'kettlebell', 'Free Weights', 'Cast iron kettlebells in various weights for ballistic and strength exercises.', 8, 'excellent', 'Gym Floor', TRUE, TRUE, 16)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Medicine Ball', 'medicine-ball', 'Functional', 'Weighted medicine balls for rotational throws, slams, and core exercises.', 4, 'good', 'Gym Floor', TRUE, TRUE, 17)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Pull-Up Bar / Chin-Up Station', 'pull-up-bar', 'Strength', 'Sturdy pull-up bar station with multiple grip positions for bodyweight back and arm exercises.', 2, 'excellent', 'Gym Floor', TRUE, TRUE, 18)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Battle Ropes', 'battle-ropes', 'Functional', 'Heavy-duty battle ropes for high-intensity cardio and arm conditioning.', 2, 'good', 'Gym Floor', TRUE, TRUE, 19)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Box Platform / Plyo Box', 'box-platform', 'Functional', 'Wooden plyometric box for box jumps, step-ups, and explosive leg training.', 3, 'good', 'Gym Floor', TRUE, TRUE, 20)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Ab Wheel', 'ab-wheel', 'Functional', 'Compact ab wheel roller for advanced core strengthening exercises.', 3, 'excellent', 'Gym Floor', TRUE, TRUE, 21)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Foam Roller', 'foam-roller', 'Recovery', 'High-density foam roller for self-myofascial release and muscle recovery.', 4, 'excellent', 'Recovery Area', TRUE, TRUE, 22)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Slam Ball', 'slam-ball', 'Functional', 'Dead-bounce slam balls for explosive slams, squats, and full-body conditioning.', 4, 'good', 'Gym Floor', TRUE, TRUE, 23)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Weight Sled', 'sled', 'Functional', 'Heavy-duty weight sled for pushing and pulling drills to build explosive power.', 1, 'good', 'Gym Floor', TRUE, TRUE, 24)
  ON CONFLICT (slug) DO NOTHING;

  VALUES ('Cable Rope Attachment', 'cable-rope-attachment', 'Functional', 'Rope attachment for cable machines for tricep pushdowns, face pulls, and core work.', 4, 'excellent', 'Gym Floor', TRUE, TRUE, 25)
  ON CONFLICT (slug) DO NOTHING;

  SELECT id INTO exercise_mat_id FROM equipment WHERE slug = 'exercise-mat';
  SELECT id INTO resistance_bands_id FROM equipment WHERE slug = 'resistance-bands';
  SELECT id INTO kettlebell_id FROM equipment WHERE slug = 'kettlebell';
  SELECT id INTO medicine_ball_id FROM equipment WHERE slug = 'medicine-ball';
  SELECT id INTO pull_up_bar_id FROM equipment WHERE slug = 'pull-up-bar';
  SELECT id INTO battle_ropes_id FROM equipment WHERE slug = 'battle-ropes';
  SELECT id INTO box_platform_id FROM equipment WHERE slug = 'box-platform';
  SELECT id INTO ab_wheel_id FROM equipment WHERE slug = 'ab-wheel';
  SELECT id INTO foam_roller_id FROM equipment WHERE slug = 'foam-roller';
  SELECT id INTO slam_ball_id FROM equipment WHERE slug = 'slam-ball';
  SELECT id INTO sled_id FROM equipment WHERE slug = 'sled';
  SELECT id INTO cable_rope_attachment_id FROM equipment WHERE slug = 'cable-rope-attachment';

  -- Chest Exercises

  -- Back Exercises

  -- Shoulders Exercises

  -- Legs Exercises

  -- Arms Exercises

  -- Core Exercises

  -- Cardio Exercises

  -- Glutes Exercises

  -- Abs Exercises

  -- Obliques Exercises
  ON CONFLICT (slug) DO NOTHING;

END $$;
